args.sparql:
SELECT ?stateLabel WHERE {
  ?plant wdt:P1349 wd:Q188983 ;  # energy source is geothermal
         wdt:P17 wd:Q30 ;         # country is United States
         wdt:P276 ?state .       # located in state
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
GROUP BY ?state ?stateLabel
ORDER BY DESC(COUNT(?plant))
LIMIT 1

SELECT ?stateLabel WHERE {
  ?plant wdt:P1349 wd:Q188983 ;
         wdt:P276 ?state .
  ?state wdt:P17 wd:Q30 ;
         rdfs:label ?stateLabel .
  FILTER (LANG(?stateLabel) = 'en')
}
GROUP BY ?state ?stateLabel
ORDER BY DESC(COUNT(?plant))
LIMIT 1

